+            return Err(PaneOperationError {
+                operation_id,
+                kind,
+                touched_nodes,
+                before_hash,
+                after_hash: self.state_hash(),
+                reason: PaneOperationFailure::Validation(err),
+            });
+        }
+
+        Ok(())
